import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSSecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        String userInput = request.getParameter("input");
        out.println("<html>");
        out.println("<body>");
        // Proper encoding to prevent XSS
        out.println("<h1>Hello " + encodeHtml(userInput) + "!</h1>");
        out.println("</body>");
        out.println("</html>");

    }

    // Method to properly encode user input for HTML output
    private String encodeHtml(String input) {
        if (input == null) {
            return "";
        }
        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
